import{_ as a}from"./plugin-vue_export-helper-c27b6911.js";import{o as e,c as n,e as s}from"./app-be253e4c.js";const o={},c=s(`<h1 id="ip命令" tabindex="-1"><a class="header-anchor" href="#ip命令" aria-hidden="true">#</a> ip命令</h1><p><code>ip</code>命令与<code>ifconfig</code>命令类似，但比<code>ifconfig</code>命令更加强大，主要功能是用于显示或设置网络设备、路由和隧道的配置等，<code>ip</code>命令是<code>Linux</code>加强版的的网络配置工具，用于代替<code>ifconfig</code>命令。</p><h2 id="语法" tabindex="-1"><a class="header-anchor" href="#语法" aria-hidden="true">#</a> 语法</h2><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">ip</span> <span class="token punctuation">[</span> OPTIONS <span class="token punctuation">]</span> OBJECT <span class="token punctuation">{</span> COMMAND <span class="token operator">|</span> <span class="token builtin class-name">help</span> <span class="token punctuation">}</span>
<span class="token function">ip</span> <span class="token punctuation">[</span> <span class="token parameter variable">-force</span> <span class="token punctuation">]</span> <span class="token parameter variable">-batch</span> filename

OBJECT :<span class="token operator">=</span> <span class="token punctuation">{</span> <span class="token function">link</span> <span class="token operator">|</span> addr <span class="token operator">|</span> addrlabel <span class="token operator">|</span> route <span class="token operator">|</span> rule <span class="token operator">|</span> neigh <span class="token operator">|</span> ntable <span class="token operator">|</span> tunnel <span class="token operator">|</span> tuntap <span class="token operator">|</span> maddr <span class="token operator">|</span> mroute <span class="token operator">|</span> mrule <span class="token operator">|</span> monitor <span class="token operator">|</span> xfrm <span class="token operator">|</span> netns <span class="token punctuation">}</span>

OPTIONS :<span class="token operator">=</span> <span class="token punctuation">{</span> -V<span class="token punctuation">[</span>ersion<span class="token punctuation">]</span> <span class="token operator">|</span> -s<span class="token punctuation">[</span>tatistics<span class="token punctuation">]</span> <span class="token operator">|</span> -r<span class="token punctuation">[</span>esolve<span class="token punctuation">]</span> <span class="token operator">|</span> -f<span class="token punctuation">[</span>amily<span class="token punctuation">]</span> <span class="token punctuation">{</span> inet <span class="token operator">|</span> inet6 <span class="token operator">|</span> ipx <span class="token operator">|</span> dnet <span class="token operator">|</span> <span class="token function">link</span> <span class="token punctuation">}</span> <span class="token operator">|</span> -o<span class="token punctuation">[</span>neline<span class="token punctuation">]</span> <span class="token punctuation">}</span>
</code></pre></div><h2 id="参数" tabindex="-1"><a class="header-anchor" href="#参数" aria-hidden="true">#</a> 参数</h2><h3 id="options" tabindex="-1"><a class="header-anchor" href="#options" aria-hidden="true">#</a> OPTIONS</h3><ul><li><code>-b, -batch &lt;FILENAME&gt;</code>: 从提供的文件或标准输入读取命令并调用它们，第一次失败将导致<code>ip</code>执行终止。</li><li><code>-force</code>: 不要在批处理模式下因错误而终止<code>ip</code>，如果在执行命令期间发生任何错误，则应用程序返回码将为非零。</li><li><code>-s, -stats, -statistics</code>: 输出更多信息，如果该选项出现两次或更多次，则信息量会增加，通常，信息是统计信息或一些时间值。</li><li><code>-l, -loops &lt;COUNT&gt;</code>: 指定<code>ip addr flush</code>逻辑在放弃之前尝试的最大循环数，默认值为<code>10</code>，<code>0</code>表示循环直到删除所有地址。</li><li><code>-f, -family &lt;FAMILY&gt;</code>: 指定使用的协议族，协议族标识符可以是<code>inet</code>、<code>inet6</code>、<code>bridge</code>、<code>ipx</code>、<code>dnet</code>或<code>link</code>中的一个，如果该选项不存在，则根据其他参数猜测协议族，如果命令行的其余部分没有提供足够的信息来猜测家族，<code>ip</code>将退回到默认的<code>ip</code>设置，通常是<code>inet</code>或<code>any</code>，<code>link</code>是一种特殊的族标识符，不涉及任何网络协议。</li><li><code>-4</code>: <code>-family inet</code>的快捷方式。</li><li><code>-6</code>: <code>-family inet6</code>的快捷方式。</li><li><code>-B</code>: <code>-family bridge</code>的快捷方式。</li><li><code>-D</code>: <code>-family decnet</code>的快捷方式。</li><li><code>-I</code>: <code>-family ipx</code>的快捷方式。</li><li><code>-0</code>: <code>-family link</code>的快捷方式。</li><li><code>-o, -oneline</code>: 将每条记录输出为一行，用<code>\\</code>字符替换换行符，当使用<code>wc</code>计数记录或<code>grep</code>输出时，这很方便。</li><li><code>-r, -resolve</code>: 使用系统的名称解析程序打印<code>DNS</code>名称而不是主机地址。</li><li><code>-V, -Version</code>: 输出版本信息。</li></ul><h3 id="object" tabindex="-1"><a class="header-anchor" href="#object" aria-hidden="true">#</a> OBJECT</h3><ul><li><code>address</code>: 设备上的协议地址，<code>IP</code>或<code>IPv6</code>。</li><li><code>addrlabel</code>: 用于协议地址选择的标签配置。</li><li><code>l2tp</code>: IP隧道以太网<code>L2TPv3</code>。</li><li><code>link</code>: 网络设备。</li><li><code>maddress</code>: 多播地址。</li><li><code>monitor</code>: 监视<code>netlink</code>消息。</li><li><code>mroute</code>: 多播路由缓存项。</li><li><code>mrule</code>: 多播路由策略数据库中的规则。</li><li><code>neighbour</code>: 管理<code>ARP</code>或<code>NDISC</code>缓存项。</li><li><code>netns</code>: 管理网络名称空间。</li><li><code>ntable</code>: 管理邻居缓存的操作。</li><li><code>route</code>: 路由表条目。</li><li><code>rule</code>: 路由策略数据库中的规则。</li><li><code>tcp_metrics/tcpmetrics</code>: 管理<code>TCP</code>指标。</li><li><code>tunnel</code>: <code>IP</code>隧道。</li><li><code>tuntap</code>: 管理<code>TUN/TAP</code>设备。</li><li><code>xfrm</code>: 管理<code>IPSec</code>策略。</li></ul><h2 id="示例" tabindex="-1"><a class="header-anchor" href="#示例" aria-hidden="true">#</a> 示例</h2><p>查看网络接口信息，例如<code>IP</code>地址，子网等。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">ip</span> addr show
</code></pre></div><p>要查看<code>eth0</code>网卡信息。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">ip</span> addr show eth0
</code></pre></div><p>启用网络接口。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">ip</span> <span class="token function">link</span> <span class="token builtin class-name">set</span> eth0 up
</code></pre></div><p>关闭网络接口。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">ip</span> <span class="token function">link</span> <span class="token builtin class-name">set</span> eth0 down
</code></pre></div><p>查看路由和默认网关信息。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">ip</span> route show
</code></pre></div><p>获取到特定<code>ip</code>的路由信息。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">ip</span> route get to <span class="token number">192.168</span>.111.111
</code></pre></div><p>查看<code>arp</code>条目。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">ip</span> neigh
</code></pre></div><p>查看网络统计。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">ip</span> <span class="token parameter variable">-s</span> <span class="token function">link</span>
</code></pre></div><p>查看详细帮助信息。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">man</span> <span class="token function">ip</span>
</code></pre></div>`,28),t=[c];function p(d,l){return e(),n("div",null,t)}const u=a(o,[["render",p],["__file","ip.html.vue"]]);export{u as default};
